_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // Remember the exact, original blue channel value.
    float orig_blue = texture(sampler_main, vUv).z;

    // Warp the vUv coordinate using the gradient of the blue channel over
    //   a fairly large sampling area.
    // (Custom shapes are being drawn that apply big blue splotches of color,
    //   which will be used here to create swirling vortices.  However, the
    //   actual blue channel will be hidden from view by the composite shader.)
    // First, fetch the gradient.
    float scale = 1.5;
    vec3 d = vec3(uTexSize.zw, 0) * 32 * scale;
    vec3 gx = texture(sampler_blur2, vUv + d.xz) -
                texture(sampler_blur2, vUv - d.xz);
    vec3 gy = texture(sampler_blur2, vUv + d.zy) -
                texture(sampler_blur2, vUv - d.zy);
    // Next, warp the UV coord by applying the gradient, rotated 90 degrees,
    // creating vortices.
    vUv.x += gy.z * uTexSize.zw * 256*2/scale;
    vUv.y -= gx.z * uTexSize.zw * 256*2/scale;
    ret = texture(sampler_main, vUv);

    // Add in some dithering.
    //vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;
    //ret += (texture(sampler_noise_lq, dither_uv).xyz-0.5)/256.0*3;

    // Keep the original blue channel.
    ret.z = orig_blue;

    // Darken over uTime.
    ret -= 0.002 * (uFrame % 2);

    // Push blue channel toward 0.5, slowly over uTime.
    ret.z = mix(ret.z, 0.5, 0.003 * (uFrame % 2));

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture(sampler_main, vUv).xyz;

    // Synthesize a fake blue channel from a combination of the red and green channels.
    // This both creates a nice color palette, and hides the fact that we're using
    // the blue channel to drive movement.
    ret.z = (ret.y - ret.x)*2.5;

    ret *= 1.7; // brighten it up.

  fragColor = ret;
}
